namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeCategory
{
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public string Icon { get; set; } = string.Empty;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly List<RecipeCategory> _categories;

    public RecipeService()
    {
        _categories = new List<RecipeCategory>
        {
            new() { Name = "Breakfast", Description = "Start your day right", Icon = "🥞" },
            new() { Name = "Lunch", Description = "Midday meals and light bites", Icon = "🥗" },
            new() { Name = "Dinner", Description = "Hearty evening dishes", Icon = "🍝" },
            new() { Name = "Desserts", Description = "Sweet treats and baked goods", Icon = "🍰" },
            new() { Name = "Snacks", Description = "Quick bites between meals", Icon = "🍿" },
            new() { Name = "Drinks", Description = "Refreshing beverages", Icon = "🥤" }
        };

        _recipes = new List<Recipe>
        {
            new() { Id = 1, Title = "Classic Pancakes", Category = "Breakfast", Ingredients = "2 cups flour
2 eggs
1.5 cups milk
2 tbsp butter
2 tbsp sugar
1 tsp baking powder", Steps = "1. Mix dry ingredients
2. Whisk eggs and milk together
3. Combine wet and dry ingredients
4. Cook on greased griddle until bubbles form
5. Flip and cook until golden", AverageRating = 4.5, RatingCount = 12 },
            new() { Id = 2, Title = "Caesar Salad", Category = "Lunch", Ingredients = "1 head romaine lettuce
1/2 cup croutons
1/4 cup parmesan
Caesar dressing
Grilled chicken (optional)", Steps = "1. Wash and chop romaine lettuce
2. Toss with Caesar dressing
3. Add croutons and parmesan
4. Top with grilled chicken if desired", AverageRating = 4.2, RatingCount = 8 },
            new() { Id = 3, Title = "Spaghetti Bolognese", Category = "Dinner", Ingredients = "400g spaghetti
500g ground beef
1 can crushed tomatoes
1 onion
3 cloves garlic
Olive oil
Italian seasoning", Steps = "1. Cook spaghetti according to package
2. Sauté onion and garlic in olive oil
3. Brown ground beef
4. Add tomatoes and seasoning
5. Simmer 20 minutes
6. Serve sauce over pasta", AverageRating = 4.8, RatingCount = 24 },
            new() { Id = 4, Title = "Chocolate Chip Cookies", Category = "Desserts", Ingredients = "2.25 cups flour
1 cup butter
3/4 cup sugar
3/4 cup brown sugar
2 eggs
1 tsp vanilla
1 tsp baking soda
2 cups chocolate chips", Steps = "1. Cream butter and sugars
2. Beat in eggs and vanilla
3. Mix in flour and baking soda
4. Fold in chocolate chips
5. Drop spoonfuls on baking sheet
6. Bake at 375°F for 9-11 minutes", AverageRating = 4.9, RatingCount = 31 },
            new() { Id = 5, Title = "Guacamole", Category = "Snacks", Ingredients = "3 ripe avocados
1 lime
1/2 onion
2 tomatoes
Cilantro
Salt
Jalapeño (optional)", Steps = "1. Mash avocados in a bowl
2. Dice onion, tomatoes, and cilantro
3. Mix into avocado
4. Squeeze lime juice over mixture
5. Season with salt
6. Add diced jalapeño for heat", AverageRating = 4.6, RatingCount = 15 },
            new() { Id = 6, Title = "Iced Latte", Category = "Drinks", Ingredients = "2 shots espresso
1 cup milk
Ice
Syrup (optional)", Steps = "1. Brew espresso and let cool slightly
2. Fill glass with ice
3. Pour milk over ice
4. Add espresso on top
5. Add flavored syrup if desired
6. Stir and enjoy", AverageRating = 4.3, RatingCount = 9 }
        };
    }

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }

    public void RateRecipe(int recipeId, int rating)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null)
        {
            var totalRating = recipe.AverageRating * recipe.RatingCount;
            recipe.RatingCount++;
            recipe.AverageRating = (totalRating + rating) / recipe.RatingCount;
        }
    }
}

