@page "/category/{CategoryName}"
@using RecipeCommunity.Services

@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes - Recipe Community</PageTitle>

<div class="container">
    <nav class="breadcrumb">
        <a href="/">Home</a> &rsaquo; <span>@CategoryName</span>
    </nav>

    <h1>@CategoryName Recipes</h1>

    @if (recipes.Any())
    {
        <div class="recipe-list">
            @foreach (var recipe in recipes)
            {
                <a href="/recipe/@recipe.Id" class="recipe-card">
                    <h3>@recipe.Title</h3>
                    <div class="recipe-meta">
                        <span class="stars">@GetStars(recipe.AverageRating)</span>
                        <span class="rating-text">@recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
                    </div>
                </a>
            }
        </div>
    }
    else
    {
        <p class="empty-state">No recipes in this category yet. <a href="/submit">Be the first to submit one!</a></p>
    }
</div>

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private List<RecipeCommunity.Models.Recipe> recipes = new();

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }

    private string GetStars(double rating)
    {
        int full = (int)rating;
        return new string('★', full) + new string('☆', 5 - full);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services

@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - Recipe Community</PageTitle>

<div class="container">
    @if (recipe is not null)
    {
        <nav class="breadcrumb">
            <a href="/">Home</a> &rsaquo; <a href="/category/@recipe.Category.ToLower()">@recipe.Category</a> &rsaquo; <span>@recipe.Title</span>
        </nav>

        <article class="recipe-detail">
            <h1>@recipe.Title</h1>

            <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />

            <section class="recipe-section">
                <h2>🧾 Ingredients</h2>
                <ul class="ingredients-list">
                    @foreach (var ingredient in recipe.Ingredients.Split('\n'))
                    {
                        <li>@ingredient</li>
                    }
                </ul>
            </section>

            <section class="recipe-section">
                <h2>👨‍🍳 Steps</h2>
                <ol class="steps-list">
                    @foreach (var step in recipe.Steps.Split('\n'))
                    {
                        var text = step.Contains(". ") ? step[(step.IndexOf(". ") + 2)..] : step;
                        <li>@text</li>
                    }
                </ol>
            </section>
        </article>
    }
    else
    {
        <p class="empty-state">Recipe not found.</p>
    }
</div>

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeCommunity.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Models
@using RecipeCommunity.Services

@inject RecipeService RecipeService

<PageTitle>Submit a Recipe - Recipe Community</PageTitle>

<div class="container">
    <nav class="breadcrumb">
        <a href="/">Home</a> &rsaquo; <span>Submit Recipe</span>
    </nav>

    <h1>📝 Submit a Recipe</h1>

    @if (submitted)
    {
        <div class="success-message">
            <h2>✅ Recipe Submitted!</h2>
            <p>Thank you for sharing "<strong>@newRecipe.Title</strong>" with our community!</p>
            <a href="/" class="btn-primary">Back to Home</a>
        </div>
    }
    else
    {
        <EditForm Model="newRecipe" OnValidSubmit="HandleSubmit" class="recipe-form">
            <DataAnnotationsValidator />

            <div class="form-group">
                <label for="title">Recipe Title</label>
                <InputText id="title" @bind-Value="newRecipe.Title" placeholder="e.g., Grandma's Apple Pie" class="form-control" />
                <ValidationMessage For="() => newRecipe.Title" />
            </div>

            <div class="form-group">
                <label for="category">Category</label>
                <InputSelect id="category" @bind-Value="newRecipe.Category" class="form-control">
                    <option value="">-- Select a category --</option>
                    @foreach (var cat in RecipeService.GetCategories())
                    {
                        <option value="@cat.Name">@cat.Name</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => newRecipe.Category" />
            </div>

            <div class="form-group">
                <label for="ingredients">Ingredients (one per line)</label>
                <InputTextArea id="ingredients" @bind-Value="newRecipe.Ingredients" rows="6" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" class="form-control" />
                <ValidationMessage For="() => newRecipe.Ingredients" />
            </div>

            <div class="form-group">
                <label for="steps">Steps (one per line)</label>
                <InputTextArea id="steps" @bind-Value="newRecipe.Steps" rows="6" placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;3. Add wet ingredients" class="form-control" />
                <ValidationMessage For="() => newRecipe.Steps" />
            </div>

            <button type="submit" class="btn-primary">Submit Recipe</button>
        </EditForm>
    }
</div>

@code {
    private Recipe newRecipe = new();
    private bool submitted = false;

    private void HandleSubmit()
    {
        if (!string.IsNullOrWhiteSpace(newRecipe.Title) &&
            !string.IsNullOrWhiteSpace(newRecipe.Category) &&
            !string.IsNullOrWhiteSpace(newRecipe.Ingredients) &&
            !string.IsNullOrWhiteSpace(newRecipe.Steps))
        {
            RecipeService.AddRecipe(newRecipe);
            submitted = true;
        }
    }
}

